package form;
import controller.*;import koneksi.Koneksi;import model.Siswa;import util.UIUtils;import javax.swing.*;import javax.swing.table.*;import java.awt.*;import java.sql.*;
public class SiswaForm extends JPanel{DefaultTableModel m=new DefaultTableModel(new String[]{"ID","NIS","Nama","Kelas","JK","Alamat"},0);SiswaController c=new SiswaController();public SiswaForm(){setLayout(new BorderLayout());JPanel p=UIUtils.page("Data Master");JTabbedPane tabs=new JTabbedPane();tabs.addTab("Data Siswa",siswaPanel());tabs.addTab("Data Kelas",new KelasForm());tabs.addTab("Kategori Tarif",simpleCrud("Kategori Pemasukan","kategori_pemasukan",new String[]{"nama_kategori","nominal_default"}));tabs.addTab("Kategori Pengeluaran",simpleCrud("Kategori Pengeluaran","kategori_pengeluaran",new String[]{"nama_kategori"}));tabs.addTab("Chart of Account",simpleCrud("Daftar Akun","chart_of_account",new String[]{"kode_akun","nama_akun","tipe"}));p.add(tabs);add(p);}JPanel siswaPanel(){JPanel p=new JPanel(new BorderLayout(8,8));p.setOpaque(false);JTextField nis=UIUtils.textField(8),nama=UIUtils.textField(18),kelas=UIUtils.textField(4),alamat=UIUtils.textField(20),search=UIUtils.textField(16);JComboBox<String> jk=new JComboBox<>(new String[]{"L","P"});JButton sim=UIUtils.button("Simpan",UIUtils.BLUE),del=UIUtils.button("Hapus ID",UIUtils.RED);sim.addActionListener(e->{try{c.simpan(new Siswa(0,nis.getText(),nama.getText(),Integer.parseInt(kelas.getText()),(String)jk.getSelectedItem(),alamat.getText(),null));load();}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});del.addActionListener(e->{String id=JOptionPane.showInputDialog(this,"ID Siswa");try{if(id!=null)c.hapus(Integer.parseInt(id));load();}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});JTable table=new JTable(m);TableRowSorter<TableModel> sorter=new TableRowSorter<>(m);table.setRowSorter(sorter);UIUtils.bindSearch(search,sorter);p.add(UIUtils.toolbar(UIUtils.formLabel("NIS"),nis,UIUtils.formLabel("Nama"),nama,UIUtils.formLabel("ID Kelas"),kelas,UIUtils.formLabel("JK"),jk,UIUtils.formLabel("Alamat"),alamat,sim,del,UIUtils.formLabel("Cari"),search),BorderLayout.NORTH);p.add(UIUtils.tableScroll(table));load();return p;}void load(){m.setRowCount(0);try{for(Object[] r:c.cari(""))m.addRow(r);}catch(Exception ignored){}}JPanel simpleCrud(String title,String table,String[] cols){JPanel p=new JPanel(new BorderLayout());DefaultTableModel dm=new DefaultTableModel();JTable jt=new JTable(dm);JTextField[] fs=new JTextField[cols.length];JPanel bar=new JPanel(new FlowLayout(FlowLayout.LEFT));for(int i=0;i<cols.length;i++){fs[i]=UIUtils.textField(10);bar.add(UIUtils.formLabel(cols[i]));bar.add(fs[i]);}JButton add=UIUtils.button("Tambah "+title,UIUtils.BLUE);add.addActionListener(e->{StringBuilder sql=new StringBuilder("INSERT INTO "+table+"(");for(String col:cols)sql.append(col).append(',');sql.setLength(sql.length()-1);sql.append(") VALUES(");sql.append("?,".repeat(cols.length));sql.setLength(sql.length()-1);sql.append(')');try(PreparedStatement ps=Koneksi.getConnection().prepareStatement(sql.toString())){for(int i=0;i<cols.length;i++)ps.setString(i+1,fs[i].getText());ps.executeUpdate();reload(dm,table);}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});bar.add(add);p.add(bar,BorderLayout.NORTH);p.add(UIUtils.tableScroll(jt));reload(dm,table);return p;}void reload(DefaultTableModel dm,String table){dm.setRowCount(0);dm.setColumnCount(0);try(PreparedStatement ps=Koneksi.getConnection().prepareStatement("SELECT * FROM "+table);ResultSet rs=ps.executeQuery()){ResultSetMetaData md=rs.getMetaData();for(int i=1;i<=md.getColumnCount();i++)dm.addColumn(md.getColumnName(i));while(rs.next()){Object[] row=new Object[md.getColumnCount()];for(int i=0;i<row.length;i++)row[i]=rs.getObject(i+1);dm.addRow(row);}}catch(Exception ignored){}}}
